import java.util.ArrayList;
import java.util.List;

public class Solution {
    public List<Integer> largestLexSequence(int n) {
        List<Integer> res = new ArrayList<Integer>(n);
        for (int i = 0; i < n; ++i) {
            res.add(i % 2);
        }
        return res;
    }
}
```

